"use strict";function switchTab(e){["plan","calc","about"].forEach(t=>{document.getElementById("panel-"+t).classList.toggle("active",t===e),document.getElementById("tab-"+t).classList.toggle("active",t===e)})}function initDropdowns(){document.getElementById("sel-grade").addEventListener("change",function(){const e=this.value,t=e?ksOf(e):null,n=document.getElementById("ks-wrap"),o=document.getElementById("ks-badge"),l=document.getElementById("sel-subject");l.innerHTML='<option value="">— Subject —</option>',document.getElementById("sel-week").innerHTML='<option value="">— Wk —</option>',e&&DB[e]?(n.style.display="block",o.textContent=ksLabel(t),DB[e].subjects.forEach(e=>{const t=document.createElement("option");t.value=e,t.textContent=e,l.appendChild(t)})):n.style.display="none",document.getElementById("doc-lbl").textContent=e?`Grade ${e} · ${ksLabel(t)||""}`:"Select grade & subject to begin";const d=document.getElementById("calc-ks1-note"),a=document.getElementById("calc-fields").querySelectorAll("input");t&&1===t?(d.style.display="block",a.forEach(e=>e.disabled=!0)):(d.style.display="none",a.forEach(e=>e.disabled=!1))}),document.getElementById("sel-q").addEventListener("change",function(){const e=document.getElementById("sel-week");if(e.innerHTML='<option value="">— Wk —</option>',this.value)for(let t=1;t<=10;t++){const n=document.createElement("option");n.value=t,n.textContent=`Week ${t}`,e.appendChild(n)}})}function computeGrade(){const e=+document.getElementById("ww-raw").value||0,t=+document.getElementById("ww-total").value||1,n=+document.getElementById("pt-raw").value||0,o=+document.getElementById("pt-total").value||1,l=+document.getElementById("st-raw").value||0,d=+document.getElementById("st-total").value||1;if(!document.getElementById("ww-total").value)return;const a=e/t*100,c=n/o*100,s=l/d*100,u=.2*a+.5*c+.3*s,i=transmute(u);document.getElementById("grade-result").style.display="block",document.getElementById("grade-val").textContent=i.toFixed(2)+"%";const m=i>=75,r=document.getElementById("grade-status");r.textContent=m?"✓ Passed":"✗ Did Not Meet Standards",r.style.color=m?"#4ade80":"#f87171",document.getElementById("grade-breakdown").textContent=`WW: ${a.toFixed(1)}% · PT: ${c.toFixed(1)}% · ST: ${s.toFixed(1)}% · Initial: ${u.toFixed(2)}%`}function transmute(e){if(e>=100)return 100;const t=[[100,100],[98.4,99],[96.8,98],[95.2,97],[93.6,96],[92,95],[90.4,94],[88.8,93],[87.2,92],[85.6,91],[84,90],[82.4,89],[80.8,88],[79.2,87],[77.6,86],[76,85],[74.4,84],[72.8,83],[71.2,82],[69.6,81],[68,80],[66.4,79],[64.8,78],[63.2,77],[61.6,76],[60,75],[56,74],[52,73],[48,72],[44,71],[40,70],[36,69],[32,68],[28,67],[24,66],[20,65],[16,64],[12,63],[8,62],[4,61],[0,60]];for(const[n,o]of t)if(e>=n)return o;return 60}